const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const headers = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };

// Calculate date 3 days ago
const now = new Date();
const threeDaysAgo = new Date(now);
threeDaysAgo.setDate(threeDaysAgo.getDate() - 3);
const cutoffDate = threeDaysAgo.toISOString().split('T')[0];

try {
  const leadsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: CRM + '/api/leads?enrolled=1&review_requested=&enrollment_date_before=' + cutoffDate,
    headers: headers,
    json: true
  });

  let leads = leadsResp.data || [];
  if (!Array.isArray(leads)) leads = [leads];

  // Filter: enrolled=true, review_requested is empty/not 'sent', enrollment_date <= 3 days ago
  leads = leads.filter(lead => {
    const enrolled = lead.enrolled == 1 || lead.enrolled === true;
    const notRequested = !lead.review_requested || lead.review_requested !== 'sent';
    const enrolledLongEnough = lead.enrollment_date && new Date(lead.enrollment_date) <= threeDaysAgo;
    return enrolled && notRequested && enrolledLongEnough;
  });

  if (leads.length === 0) {
    return [{ json: { _hasLeads: false, leads: [], total: 0 } }];
  }

  return [{ json: { _hasLeads: true, leads: leads, total: leads.length } }];
} catch(e) {
  return [{ json: { _hasLeads: false, leads: [], total: 0, error: e.message } }];
}

const data = $input.first().json;
const leads = data.leads;
const CRM = $env.CRM_API_URL;
const API_KEY = $env.CRM_API_KEY;
const crmHeaders = { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' };
const today = $now.toFormat('yyyy-MM-dd');

let sentCount = 0;
let failedCount = 0;
const failedNames = [];

for (const lead of leads) {
  if (!lead.phone) {
    failedCount++;
    failedNames.push(lead.student_name + ' (no phone)');
    continue;
  }

  try {
    // Send WhatsApp approved template
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v19.0/' + $env.WHATSAPP_PHONE_NUMBER_ID + '/messages',
      headers: {
        'Authorization': 'Bearer ' + $env.WHATSAPP_ACCESS_TOKEN,
        'Content-Type': 'application/json'
      },
      body: {
        messaging_product: 'whatsapp',
        to: lead.phone,
        type: 'template',
        template: {
          name: 'review_request_v1',
          language: { code: 'en' },
          components: [
            {
              type: 'body',
              parameters: [
                { type: 'text', text: lead.student_name || 'Student' },
                { type: 'text', text: $env.GOOGLE_REVIEW_URL || '' }
              ]
            }
          ]
        }
      },
      json: true
    });

    // Update lead: review_requested = sent
    await this.helpers.httpRequest({
      method: 'POST',
      url: CRM + '/api/leads',
      body: {
        phone: lead.phone,
        review_requested: 'sent',
        review_request_date: today
      },
      headers: crmHeaders,
      json: true
    });

    // Log to posting
    await this.helpers.httpRequest({
      method: 'POST',
      url: CRM + '/api/posting',
      body: {
        platform: 'whatsapp_review',
        status: 'sent',
        date: today,
        brand: 'extrabits_academy',
        content_item: lead.student_name || '',
        area: ''
      },
      headers: crmHeaders,
      json: true
    });

    sentCount++;

  } catch (error) {
    failedCount++;
    failedNames.push(lead.student_name + ' (' + lead.phone + ')');

    // Telegram alert for failures
    try {
      await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
        body: {
          chat_id: $env.TELEGRAM_CHAT_ID,
          text: '⚠️ Review request failed for ' + (lead.student_name || 'Unknown') + ' (' + lead.phone + ')'
        },
        json: true
      });
    } catch(tgErr) {}
  }
}

return [{ json: { sent: sentCount, failed: failedCount, failedNames: failedNames } }];

const result = $input.first().json;

const summaryText = '⭐ Review Requests Summary — ' + $now.toFormat('yyyy-MM-dd') + '\n\n' +
  '✅ Sent: ' + result.sent + ' students contacted\n' +
  (result.failed > 0 ? '❌ Failed: ' + result.failed + '\n' + 'Failed: ' + result.failedNames.join(', ') : '🎉 All successful!') +
  '\n\nStudents will receive the review request via WhatsApp.';

await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage',
  body: { chat_id: $env.TELEGRAM_CHAT_ID, text: summaryText },
  json: true
});

return [{ json: { status: 'complete', ...result } }];
